import React, { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import axios from "axios";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

export default function RoomDetails() {
  const { id } = useParams();

  const [room, setRoom] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    if (!id) {
      setError("Invalid room ID");
      setLoading(false);
      return;
    }

    axios
      .get(`${API_BASE}/api/rooms/${id}/`)
      .then((res) => {
        setRoom(res.data);
      })
      .catch((err) => {
        console.error("API Error:", err);
        setError("Room not found");
      })
      .finally(() => {
        setLoading(false);
      });
  }, [id]);

  if (loading) {
    return <p style={{ padding: 40 }}>Loading...</p>;
  }

  if (error) {
    return <p style={{ padding: 40 }}>{error}</p>;
  }

  if (!room) {
    return <p style={{ padding: 40 }}>No room data</p>;
  }

  const image =
    room.image
      ? room.image.startsWith("http")
        ? room.image
        : `${API_BASE}${room.image}`
      : "/assets/images/room_blur.png";

  return (
    <>
      {/* NAVIGATION */}
      <header className="nav">
        <div className="nav-inner">
          <div className="brand">
            <img
              src="/assets/images/glamp_logo.png"
              alt="Logo"
              className="logo"
            />
          </div>
          <nav className="menu">
            <Link to="/">Home</Link>
            <Link to="/reservation">Reservation</Link>
            <Link className="reserve" to="/reservation">
              Reserve
            </Link>
          </nav>
        </div>
      </header>

      {/* HERO */}
      <section
        className="hero"
        style={{
          backgroundImage: `url("${image}")`,
          backgroundSize: "cover",
          backgroundPosition: "center",
          minHeight: "80vh",
        }}
      >
        <div className="hero-overlay">
          <h1>{room.room_name}</h1>
          <p>Experience nature with unmatched comfort & elegance</p>
        </div>
      </section>

      {/* ROOM DETAILS */}
      <section className="room-details">
        <div className="room-container">
          <h2 className="room-title">{room.room_name}</h2>

          <div className="room-price-box">
            <div className="price">
              ₹{Number(room.price).toFixed(2)} / night
            </div>
            <Link to="/reservation" className="reserve-btn">
              RESERVE NOW
            </Link>
          </div>

          <p className="room-description">
            {room.description || "No description available"}
          </p>
        </div>
      </section>

      {/* AMENITIES */}
      <section className="room-amenities">
        <div className="amenities-container">
          {[
            "4 Guests",
            "35 Feet Size",
            "Connecting Rooms",
            "1 King Bed",
            "Cable TV",
            "Free WiFi",
            "Bathtub",
            "Balcony",
            "City View",
          ].map((item) => (
            <div className="amenity" key={item}>
              {item}
            </div>
          ))}
        </div>
      </section>

      {/* FOOTER */}
      <footer className="footer">
        <div className="footer-inner">
          <div>
            <h4>Address</h4>
            <p>Adimali, Idukki, Kerala</p>
          </div>
          <div>
            <h2>THE PARADISE GLAMP</h2>
            ★★★★★
          </div>
          <div>
            <h4>Contact</h4>
            <p>+91 9497185771</p>
          </div>
        </div>
      </footer>
    </>
  );
}
